export class StarlingError extends Error {
  public name = 'StarlingError'
  constructor(public code: number, public message: string, public originError?: Error) {
    super(message)
    this.code = code
    this.message = message
    this.originError = originError
    if ((Error as any).captureStackTrace) (Error as any).captureStackTrace(this, this.constructor)
  }
}

